const express = require('express');
const mongoose = require('mongoose');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';
const GENERIC_ERROR = 'Invalid credentials';

const userSchema = new mongoose.Schema({
  username: { type: String, required: true, unique: true, index: true },
  password: { type: String, required: true },
  loginAttempts: { type: Number, default: 0 },
  lockUntil: { type: Date }
});

userSchema.virtual('isLocked').get(function() {
  return !!(this.lockUntil && this.lockUntil > Date.now());
});

const User = mongoose.model('User', userSchema);

const loginAttemptSchema = new mongoose.Schema({
  identifier: { type: String, required: true, index: true },
  attempts: { type: Number, default: 0 },
  lastAttempt: { type: Date, default: Date.now },
  lockUntil: { type: Date }
});

const LoginAttempt = mongoose.model('LoginAttempt', loginAttemptSchema);

const ipRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 20,
  message: GENERIC_ERROR,
  standardHeaders: false,
  legacyHeaders: false,
  skipSuccessfulRequests: false
});

async function checkAccountRateLimit(username) {
  const now = Date.now();
  let attempt = await LoginAttempt.findOne({ identifier: username });
  
  if (!attempt) {
    attempt = new LoginAttempt({ identifier: username, attempts: 0 });
  }
  
  if (attempt.lockUntil && attempt.lockUntil > now) {
    return { allowed: false, locked: true };
  }
  
  if (attempt.lockUntil && attempt.lockUntil <= now) {
    attempt.attempts = 0;
    attempt.lockUntil = null;
  }
  
  if (now - attempt.lastAttempt.getTime() > 15 * 60 * 1000) {
    attempt.attempts = 0;
  }
  
  attempt.attempts += 1;
  attempt.lastAttempt = new Date(now);
  
  if (attempt.attempts >= 5) {
    attempt.lockUntil = new Date(now + 30 * 60 * 1000);
    await attempt.save();
    return { allowed: false, locked: true };
  }
  
  await attempt.save();
  return { allowed: true, locked: false };
}

async function resetAccountRateLimit(username) {
  await LoginAttempt.findOneAndUpdate(
    { identifier: username },
    { attempts: 0, lockUntil: null }
  );
}

async function constantTimeValidation(username, password) {
  const startTime = Date.now();
  const minDelay = 200;
  
  let user = await User.findOne({ username }).select('+password');
  let isValid = false;
  
  if (user && !user.isLocked) {
    isValid = await bcrypt.compare(password, user.password);
  } else {
    await bcrypt.compare(password, '$2b$10$abcdefghijklmnopqrstuv1234567890123456789012');
  }
  
  const elapsed = Date.now() - startTime;
  if (elapsed < minDelay) {
    await new Promise(resolve => setTimeout(resolve, minDelay - elapsed));
  }
  
  return { user, isValid };
}

app.post('/api/login', ipRateLimiter, async (req, res) => {
  try {
    const { username, password } = req.body;
    
    if (!username || !password) {
      return res.status(401).json({ error: GENERIC_ERROR });
    }
    
    const rateCheck = await checkAccountRateLimit(username);
    if (!rateCheck.allowed) {
      return res.status(401).json({ error: GENERIC_ERROR });
    }
    
    const { user, isValid } = await constantTimeValidation(username, password);
    
    if (!isValid || !user) {
      return res.status(401).json({ error: GENERIC_ERROR });
    }
    
    await resetAccountRateLimit(username);
    
    const token = jwt.sign(
      { userId: user._id, username: user.username },
      JWT_SECRET,
      { expiresIn: '1h' }
    );
    
    res.json({ token });
    
  } catch (error) {
    res.status(401).json({ error: GENERIC_ERROR });
  }
});

mongoose.connect(process.env.MONGODB_URI || 'mongodb://localhost:27017/authdb');

const PORT = process.env.PORT || 3000;
app.listen(PORT);